effect.shader:
void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float a = angle * 0.0174533;
    vec2 st = acLayerNorm;
    st -= 0.5;
    st -= (offset*vec2(1,-1)) / 500.;
    st *= scale;
    st *= mat2(
        sin(a), -cos(a),
        cos(a), sin(a)
    );
    st += 0.5;
    float t;

    if( gradType == 0 ) {
        t = st.x;
    } else if ( gradType == 1 ) {
        t = length( st - 0.5 ) * 2.0;
    } else if ( gradType == 2 ) {
        vec2 xy = st - 0.5;
        vec2 zw = vec2(0,1.0);
        float a = atan(xy.x, xy.y);
        float b = atan(zw.x, zw.y);
        t = mod(((a-b)+6.28),6.28)/6.28;
    } else {
        t = st.x;
    }

    t = clamp(t,0.0,1.0);

    vec4 color = mix(color1, color2, t);
    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*color.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-color.rgb)),1.0) * texColor.a;
    } else {
        result = vec4(color.rgb,1.0)*texColor.a;
    }
    gl_FragColor = mix(texColor,result,alpha);
}
